# Декоратор для замера времени
import time

def замерить_время(func):
    def обертка(*args, **kwargs):
        начало = time.time()
        результат = func(*args, **kwargs)
        конец = time.time()
        print(f"Время выполнения: {конец - начало:.4f} сек")
        return результат
    return обертка

@замерить_время
def пауза():
    time.sleep(1)
    print("Готово!")

пауза()

# Декоратор с параметрами
@замерить_время
def сумма_до_n(n):
    return sum(range(n + 1))

print(f"Сумма до 1000: {сумма_до_n(1000)}")

