# Timer decorator
import time

def measure_time(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"Execution time: {end - start:.4f} sec")
        return result
    return wrapper

@measure_time
def pause():
    time.sleep(1)
    print("Done!")

pause()

# Decorator with parameters
@measure_time
def sum_up_to(n):
    return sum(range(n + 1))

print(f"Sum up to 1000: {sum_up_to(1000)}")
